"use strict";(globalThis.webpackChunkdocusaurus_website=globalThis.webpackChunkdocusaurus_website||[]).push([[832],{2502(e,n,t){t.r(n),t.d(n,{assets:()=>l,contentTitle:()=>r,default:()=>h,frontMatter:()=>o,metadata:()=>s,toc:()=>c});const s=JSON.parse('{"id":"chapter-01-what-is-physical-ai","title":"Chapter 1: What is Physical AI?","description":"Learning Objectives","source":"@site/docs/chapter-01-what-is-physical-ai.md","sourceDirName":".","slug":"/chapter-01-what-is-physical-ai","permalink":"/hackathon_1/docs/chapter-01-what-is-physical-ai","draft":false,"unlisted":false,"editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/docs/chapter-01-what-is-physical-ai.md","tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"sidebar_position":1},"sidebar":"tutorialSidebar","previous":{"title":"Physical AI & Humanoid Robotics","permalink":"/hackathon_1/docs/intro"},"next":{"title":"Chapter 2: Humanoid Robotics Landscape","permalink":"/hackathon_1/docs/chapter-02-humanoid-robotics-landscape"}}');var i=t(4848),a=t(8453);const o={sidebar_position:1},r="Chapter 1: What is Physical AI?",l={},c=[{value:"Learning Objectives",id:"learning-objectives",level:2},{value:"Introduction",id:"introduction",level:2},{value:"Core Concepts",id:"core-concepts",level:2},{value:"Embodied Intelligence",id:"embodied-intelligence",level:3},{value:"Physical Laws as Design Constraints",id:"physical-laws-as-design-constraints",level:3},{value:"The Sense-Plan-Act Loop and Its Modern Alternatives",id:"the-sense-plan-act-loop-and-its-modern-alternatives",level:3},{value:"Difference from Digital/Software AI",id:"difference-from-digitalsoftware-ai",level:3},{value:"Why Physical Grounding Matters",id:"why-physical-grounding-matters",level:3},{value:"Real-World Examples of Physical AI Systems",id:"real-world-examples-of-physical-ai-systems",level:3},{value:"Hands-On: Code Example",id:"hands-on-code-example",level:2},{value:"Common Mistakes",id:"common-mistakes",level:2},{value:"Summary",id:"summary",level:2},{value:"Review Questions",id:"review-questions",level:2}];function d(e){const n={code:"code",h1:"h1",h2:"h2",h3:"h3",header:"header",li:"li",ol:"ol",p:"p",pre:"pre",strong:"strong",table:"table",tbody:"tbody",td:"td",th:"th",thead:"thead",tr:"tr",ul:"ul",...(0,a.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(n.header,{children:(0,i.jsx)(n.h1,{id:"chapter-1-what-is-physical-ai",children:"Chapter 1: What is Physical AI?"})}),"\n",(0,i.jsx)(n.h2,{id:"learning-objectives",children:"Learning Objectives"}),"\n",(0,i.jsxs)(n.ul,{children:["\n",(0,i.jsx)(n.li,{children:"Define Physical AI and distinguish it from purely software-based AI systems"}),"\n",(0,i.jsx)(n.li,{children:"Explain why physical grounding fundamentally changes the constraints and capabilities of an AI system"}),"\n",(0,i.jsx)(n.li,{children:"Identify the role of physical laws (gravity, friction, inertia) in shaping AI design decisions"}),"\n",(0,i.jsx)(n.li,{children:"Recognize real-world examples of Physical AI systems across industries"}),"\n",(0,i.jsx)(n.li,{children:"Understand why embodiment is considered a prerequisite for certain classes of intelligent behavior"}),"\n"]}),"\n",(0,i.jsx)(n.h2,{id:"introduction",children:"Introduction"}),"\n",(0,i.jsx)(n.p,{children:"Artificial intelligence, as most developers first encounter it, lives entirely inside a computer. A language model reads text and produces text. A recommendation engine processes vectors and returns ranked lists. A fraud detection system weighs features and outputs a probability score. None of these systems need to worry about whether their outputs will cause something to fall over, overheat a motor, or misjudge a slippery floor. They operate in a world of pure information, where mistakes are cheap and the laws of physics are simply irrelevant."}),"\n",(0,i.jsx)(n.p,{children:"Physical AI is the discipline that changes this assumption entirely. A physically embodied AI system must sense, reason about, and act within the physical world in real time. It must respect the hard constraints that nature imposes: gravity pulls objects downward at 9.8 m/s\xb2, motors have torque limits, friction coefficients vary between surfaces, and a robot arm that moves too fast will vibrate, overshoot, or damage itself. The moment an AI system must move a real object in the real world, every design decision \u2014 from sensor choice to control loop frequency to neural network latency \u2014 becomes tightly coupled to these physical realities."}),"\n",(0,i.jsx)(n.p,{children:"This coupling is not a limitation to be engineered around; it is the defining feature of the domain. Researchers in embodied cognition (the study of how intelligence arises through physical interaction with an environment) argue that many forms of intelligence cannot exist without a body. A robot learning to walk does not just learn a policy; it learns something about balance, momentum, surface compliance, and proprioception that no amount of text training can substitute for. This chapter lays the conceptual foundation for the entire textbook by establishing what makes Physical AI distinct, why it is hard, and why it is one of the most important frontiers in modern technology."}),"\n",(0,i.jsx)(n.h2,{id:"core-concepts",children:"Core Concepts"}),"\n",(0,i.jsx)(n.h3,{id:"embodied-intelligence",children:"Embodied Intelligence"}),"\n",(0,i.jsx)(n.p,{children:"Embodied intelligence refers to cognitive behavior that emerges from the interaction between an agent's body and its environment. The philosopher Andy Clark and roboticist Rodney Brooks both argued, from different angles, that intelligence is not a program running inside a skull (or a chip) \u2014 it is a dynamic loop between brain, body, and world."}),"\n",(0,i.jsx)(n.p,{children:"Consider how a human catches a thrown ball. You do not consciously compute the ball's parabolic trajectory using kinematics equations, then command each finger muscle individually. Instead, your visual system, cerebellum, and motor cortex operate as a tightly coupled feedback system, using the body itself as part of the computation. The body's spring-like tendons absorb impact; the eye tracks the ball with smooth pursuit; the hand pre-shapes based on predicted size. Remove the body and this intelligence disappears entirely."}),"\n",(0,i.jsx)(n.p,{children:"For AI systems, embodiment implies several things:"}),"\n",(0,i.jsxs)(n.ul,{children:["\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"Sensor-motor loops"}),": The system must continuously read sensors and update actuator commands, typically at frequencies from 100 Hz to 1 kHz for physical stability."]}),"\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"State estimation under uncertainty"}),": Physical sensors are noisy. A camera does not give you a perfect 3D world model; an IMU drifts over time. The robot must maintain a probabilistic belief about its own state and the state of the environment."]}),"\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"Real-time constraints"}),": Unlike a web API that can take 200 ms to respond, a balancing robot's control loop must close in under 5 ms or the robot falls."]}),"\n"]}),"\n",(0,i.jsx)(n.h3,{id:"physical-laws-as-design-constraints",children:"Physical Laws as Design Constraints"}),"\n",(0,i.jsx)(n.p,{children:"Every physical AI system operates inside a physics sandbox it cannot cheat. Understanding which laws matter most is essential for every engineer in this field."}),"\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"Gravity and balance"}),": Any legged or mobile robot must constantly manage its center of mass relative to its support polygon. The moment the center of mass projects outside the support polygon, the robot tips. This single constraint drives enormous amounts of humanoid robot design \u2014 why legs need to be wide, why arms need counterweights, why gait patterns look the way they do."]}),"\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"Inertia and momentum"}),": A heavy robot arm moving fast carries significant momentum. Stopping it quickly requires large braking forces, which stress joints and can cause vibration. Control algorithms must plan trajectories that respect these dynamics, not just plan geometric paths."]}),"\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"Friction and contact"}),": Robots interact with the world through contact. A hand grasping an object applies force through friction; a foot pushing off the floor uses friction to generate forward motion. Friction coefficients are uncertain and change with surface conditions. Robust Physical AI must reason about contact, not just motion through free space."]}),"\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"Thermal and power limits"}),": Motors generate heat when they produce torque. Run a motor at its torque limit continuously and it will overheat and shut down. Physical AI systems must manage energy budgets, thermal states, and power delivery \u2014 concerns that never appear in software AI."]}),"\n",(0,i.jsx)(n.h3,{id:"the-sense-plan-act-loop-and-its-modern-alternatives",children:"The Sense-Plan-Act Loop and Its Modern Alternatives"}),"\n",(0,i.jsx)(n.p,{children:"The classical architecture for physical AI is the Sense-Plan-Act (SPA) loop:"}),"\n",(0,i.jsxs)(n.ol,{children:["\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"Sense"}),": Read all sensors and construct a world model."]}),"\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"Plan"}),": Compute the optimal action given the world model and a goal."]}),"\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"Act"}),": Execute the action via actuators."]}),"\n"]}),"\n",(0,i.jsx)(n.p,{children:"This architecture works well for slow, structured environments \u2014 a robotic arm doing pick-and-place in a factory where objects are always in the same location. But it fails in dynamic, unstructured environments because the plan phase takes too long. By the time a humanoid robot has finished planning how to catch a falling cup, the cup is already on the floor."}),"\n",(0,i.jsxs)(n.p,{children:["Modern Physical AI replaces or supplements planning with ",(0,i.jsx)(n.strong,{children:"reactive control"})," (direct sensor-to-actuator mappings, often implemented as neural networks) and ",(0,i.jsx)(n.strong,{children:"model predictive control (MPC)"})," (optimize over a short time horizon, execute one step, replan). The most capable systems layer these approaches: a slow, high-level planner provides goals, while a fast, learned reactive policy handles moment-to-moment execution."]}),"\n",(0,i.jsx)(n.h3,{id:"difference-from-digitalsoftware-ai",children:"Difference from Digital/Software AI"}),"\n",(0,i.jsxs)(n.table,{children:[(0,i.jsx)(n.thead,{children:(0,i.jsxs)(n.tr,{children:[(0,i.jsx)(n.th,{children:"Dimension"}),(0,i.jsx)(n.th,{children:"Software AI"}),(0,i.jsx)(n.th,{children:"Physical AI"})]})}),(0,i.jsxs)(n.tbody,{children:[(0,i.jsxs)(n.tr,{children:[(0,i.jsx)(n.td,{children:"Operating medium"}),(0,i.jsx)(n.td,{children:"Digital data"}),(0,i.jsx)(n.td,{children:"Physical world"})]}),(0,i.jsxs)(n.tr,{children:[(0,i.jsx)(n.td,{children:"Failure modes"}),(0,i.jsx)(n.td,{children:"Wrong outputs"}),(0,i.jsx)(n.td,{children:"Damage, falls, injury"})]}),(0,i.jsxs)(n.tr,{children:[(0,i.jsx)(n.td,{children:"Latency tolerance"}),(0,i.jsx)(n.td,{children:"Seconds acceptable"}),(0,i.jsx)(n.td,{children:"Milliseconds required"})]}),(0,i.jsxs)(n.tr,{children:[(0,i.jsx)(n.td,{children:"Data collection"}),(0,i.jsx)(n.td,{children:"Cheap, scalable"}),(0,i.jsx)(n.td,{children:"Expensive, slow, dangerous"})]}),(0,i.jsxs)(n.tr,{children:[(0,i.jsx)(n.td,{children:"Iteration speed"}),(0,i.jsx)(n.td,{children:"Deploy in minutes"}),(0,i.jsx)(n.td,{children:"Hardware-in-loop testing takes hours"})]}),(0,i.jsxs)(n.tr,{children:[(0,i.jsx)(n.td,{children:"Laws of physics"}),(0,i.jsx)(n.td,{children:"Irrelevant"}),(0,i.jsx)(n.td,{children:"Central design constraint"})]})]})]}),"\n",(0,i.jsx)(n.p,{children:"This table is not just academic. It means that techniques that work brilliantly for software AI (massive datasets, rapid online A/B testing, model updates pushed to production hourly) are difficult or impossible to apply directly to physical systems without significant adaptation."}),"\n",(0,i.jsx)(n.h3,{id:"why-physical-grounding-matters",children:"Why Physical Grounding Matters"}),"\n",(0,i.jsxs)(n.p,{children:["The case for physical grounding goes beyond robots. Language models trained on text alone have no grounding in what it feels like to lift something heavy, lose balance, or feel the resistance of a stuck drawer. This leads to systematic gaps in their reasoning about physical tasks. Research in ",(0,i.jsx)(n.strong,{children:"grounded language models"})," \u2014 models trained alongside robot sensor data, video of physical interactions, and simulation \u2014 shows measurable improvements in tasks that require physical commonsense reasoning."]}),"\n",(0,i.jsx)(n.p,{children:"More broadly, many of the most consequential applications of AI in the next decade \u2014 manufacturing automation, elder care, disaster response, construction \u2014 require systems that operate physically in the world. Building those systems requires engineers who understand Physical AI as a discipline, not just AI applied to robots."}),"\n",(0,i.jsx)(n.h3,{id:"real-world-examples-of-physical-ai-systems",children:"Real-World Examples of Physical AI Systems"}),"\n",(0,i.jsxs)(n.ul,{children:["\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"Industrial robot arms (FANUC, KUKA, ABB)"}),": The most economically deployed Physical AI today. Operating in structured environments with precise repeatability."]}),"\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"Boston Dynamics Spot"}),": A quadruped robot capable of navigating unstructured terrain using a mix of model-based and learned controllers."]}),"\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"Tesla Optimus"}),": A humanoid robot designed for general-purpose labor tasks, using cameras as primary sensors and end-to-end neural network policies."]}),"\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"Waymo autonomous vehicles"}),": Physical AI operating in traffic, combining LiDAR, cameras, HD maps, and learned prediction models."]}),"\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"Surgical robots (Intuitive da Vinci)"}),": Physical AI in high-stakes environments where precision is measured in sub-millimeter increments."]}),"\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"Amazon warehouse robots"}),": Large fleets of mobile robots performing logistics tasks, coordinated by centralized planning systems."]}),"\n"]}),"\n",(0,i.jsx)(n.h2,{id:"hands-on-code-example",children:"Hands-On: Code Example"}),"\n",(0,i.jsx)(n.p,{children:"The following example simulates a basic sense-plan-act loop in Python. It models a 1D robot trying to reach a target position against gravity and friction, giving you intuition for how physical constraints enter the control loop."}),"\n",(0,i.jsx)(n.pre,{children:(0,i.jsx)(n.code,{className:"language-python",children:'# physical_ai_intro.py\n# Simulates a simple 1D Physical AI control loop.\n# A "robot" must move from position 0 to a target position,\n# dealing with gravity (if on a slope), friction, and actuator limits.\n\nimport time\nimport random\n\n# \u2500\u2500 Physical constants \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nGRAVITY = 9.8          # m/s\xb2\nMASS = 5.0             # kg \u2014 robot mass\nMAX_FORCE = 60.0       # N  \u2014 actuator torque limit\nFRICTION_COEFF = 0.25  # kinetic friction coefficient\nDT = 0.01              # seconds per simulation step (100 Hz control loop)\nSLOPE_ANGLE_DEG = 5.0  # degrees of incline\n\nimport math\nSLOPE_RAD = math.radians(SLOPE_ANGLE_DEG)\n\n# Gravity component along the slope (opposes uphill motion)\nGRAVITY_FORCE = MASS * GRAVITY * math.sin(SLOPE_RAD)\n\n# \u2500\u2500 Robot state \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nstate = {\n    "position": 0.0,   # meters along slope\n    "velocity": 0.0,   # m/s\n}\n\nTARGET_POSITION = 2.0  # meters \u2014 where the robot must reach\nKP = 40.0              # proportional gain\nKD = 8.0               # derivative gain (damping)\n\ndef sense(state: dict) -> dict:\n    """\n    Simulates noisy sensor readings.\n    Real robots use encoders, IMUs, and cameras \u2014 all with noise.\n    """\n    noise = random.gauss(0, 0.002)  # 2 mm standard deviation\n    return {\n        "position": state["position"] + noise,\n        "velocity": state["velocity"] + random.gauss(0, 0.005),\n    }\n\ndef plan(observation: dict, target: float) -> float:\n    """\n    PD controller: computes desired force given position error and velocity.\n    In a real system this might be an MPC optimizer or a neural network policy.\n    """\n    error = target - observation["position"]\n    derivative = -observation["velocity"]   # damp oscillation\n\n    # Raw desired force from PD law\n    desired_force = KP * error + KD * derivative\n\n    # Clamp to actuator limits \u2014 the robot cannot produce infinite force\n    desired_force = max(-MAX_FORCE, min(MAX_FORCE, desired_force))\n    return desired_force\n\ndef act(force: float, state: dict) -> dict:\n    """\n    Physics integrator: apply the chosen force and advance the simulation.\n    Includes friction and gravity \u2014 the physical constraints the AI must overcome.\n    """\n    # Friction opposes motion direction\n    if abs(state["velocity"]) > 1e-4:\n        friction = -FRICTION_COEFF * MASS * GRAVITY * math.cos(SLOPE_RAD) * (\n            1 if state["velocity"] > 0 else -1\n        )\n    else:\n        friction = 0.0\n\n    # Net force = actuator - gravity component - friction\n    net_force = force - GRAVITY_FORCE + friction\n\n    # Newton\'s second law: F = ma \u2192 a = F/m\n    acceleration = net_force / MASS\n\n    # Euler integration (simple but sufficient for demo)\n    state["velocity"] += acceleration * DT\n    state["position"] += state["velocity"] * DT\n\n    return state\n\n# \u2500\u2500 Main control loop \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nprint(f"{\'Step\':>5}  {\'Position\':>10}  {\'Velocity\':>10}  {\'Force\':>8}  {\'Error\':>8}")\nprint("-" * 55)\n\nfor step in range(500):  # 500 steps \xd7 0.01 s = 5 seconds of simulation\n    # SENSE: read (noisy) sensor data\n    observation = sense(state)\n\n    # PLAN: compute control output\n    force = plan(observation, TARGET_POSITION)\n\n    # ACT: apply force and advance physics\n    state = act(force, state)\n\n    # Print every 50 steps so output is readable\n    if step % 50 == 0:\n        error = TARGET_POSITION - state["position"]\n        print(f"{step:>5}  {state[\'position\']:>10.4f}  "\n              f"{state[\'velocity\']:>10.4f}  {force:>8.2f}  {error:>8.4f}")\n\n    # Check convergence\n    if abs(TARGET_POSITION - state["position"]) < 0.005 and abs(state["velocity"]) < 0.01:\n        print(f"\\nTarget reached at step {step} ({step * DT:.2f} s)")\n        break\n'})}),"\n",(0,i.jsxs)(n.p,{children:["Run this with ",(0,i.jsx)(n.code,{children:"python physical_ai_intro.py"}),". Experiment with:"]}),"\n",(0,i.jsxs)(n.ul,{children:["\n",(0,i.jsxs)(n.li,{children:["Increasing ",(0,i.jsx)(n.code,{children:"SLOPE_ANGLE_DEG"})," to see how gravity makes the task harder"]}),"\n",(0,i.jsxs)(n.li,{children:["Setting ",(0,i.jsx)(n.code,{children:"FRICTION_COEFF = 0"})," to see how the robot overshoots without damping"]}),"\n",(0,i.jsxs)(n.li,{children:["Reducing ",(0,i.jsx)(n.code,{children:"MAX_FORCE"})," below ",(0,i.jsx)(n.code,{children:"GRAVITY_FORCE"})," to see the robot fail to climb"]}),"\n"]}),"\n",(0,i.jsx)(n.h2,{id:"common-mistakes",children:"Common Mistakes"}),"\n",(0,i.jsxs)(n.ol,{children:["\n",(0,i.jsxs)(n.li,{children:["\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"Ignoring latency budgets"}),": Developers from web backgrounds often assume that a 100 ms inference time for a neural network policy is acceptable. In physical systems, 100 ms is an eternity \u2014 a falling robot travels significant distance in that time. Always profile end-to-end latency from sensor read to actuator command."]}),"\n"]}),"\n",(0,i.jsxs)(n.li,{children:["\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"Treating simulation as reality"}),': Simulators are invaluable, but they have a "reality gap." A policy trained entirely in simulation often fails on real hardware because the simulator\'s friction model, motor dynamics, and contact physics are approximations. Always plan for sim-to-real transfer as a distinct engineering challenge.']}),"\n"]}),"\n",(0,i.jsxs)(n.li,{children:["\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"Underestimating power and thermal constraints"}),": A robot demonstration that runs for 2 minutes in a lab may not sustain 8 hours of warehouse operation. Model power consumption and motor thermal limits from the start, not as an afterthought."]}),"\n"]}),"\n",(0,i.jsxs)(n.li,{children:["\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"Confusing kinematic and dynamic planning"}),": Planning a path through space (kinematics) is not the same as planning how to move through space given mass, inertia, and force limits (dynamics). Kinematic plans that look smooth on paper can be physically impossible to execute."]}),"\n"]}),"\n",(0,i.jsxs)(n.li,{children:["\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"Assuming sensors are ground truth"}),": Every physical sensor lies \u2014 encoders have backlash, cameras have motion blur, IMUs drift. Building systems that assume sensor readings are perfect leads to catastrophic failures in the field. Always model sensor uncertainty explicitly."]}),"\n"]}),"\n"]}),"\n",(0,i.jsx)(n.h2,{id:"summary",children:"Summary"}),"\n",(0,i.jsxs)(n.ul,{children:["\n",(0,i.jsx)(n.li,{children:"Physical AI is the discipline of building AI systems that sense, reason, and act within the physical world under real physical constraints."}),"\n",(0,i.jsx)(n.li,{children:"Embodied intelligence emerges from the tight coupling between a system's body, sensors, actuators, and environment \u2014 it cannot be fully replicated in software alone."}),"\n",(0,i.jsx)(n.li,{children:"Physical laws (gravity, friction, inertia, thermal limits) are not obstacles to engineer around but fundamental design parameters that shape every decision."}),"\n",(0,i.jsx)(n.li,{children:"The classical Sense-Plan-Act loop is being replaced by hybrid architectures combining model predictive control and learned reactive policies to meet real-time constraints."}),"\n",(0,i.jsx)(n.li,{children:"The gap between software AI and Physical AI is large: failure modes are physical (damage, falls), data is expensive, iteration is slow, and latency tolerance is measured in milliseconds."}),"\n"]}),"\n",(0,i.jsx)(n.h2,{id:"review-questions",children:"Review Questions"}),"\n",(0,i.jsxs)(n.ol,{children:["\n",(0,i.jsxs)(n.li,{children:["\n",(0,i.jsx)(n.p,{children:"A software AI model achieves 95% accuracy on a benchmark dataset. Explain why this metric is insufficient for evaluating a Physical AI system performing the same task on a real robot. What additional metrics would you require?"}),"\n"]}),"\n",(0,i.jsxs)(n.li,{children:["\n",(0,i.jsx)(n.p,{children:"You are designing a controller for a robot arm that must sort packages on a fast-moving conveyor belt. The conveyor moves at 1 m/s and packages are spaced 0.5 m apart. What is the maximum end-to-end latency your sense-plan-act loop can tolerate? What does this imply for your choice of perception algorithm?"}),"\n"]}),"\n",(0,i.jsxs)(n.li,{children:["\n",(0,i.jsx)(n.p,{children:"Describe two ways that physical grounding might improve a language model's ability to reason about everyday tasks. Use concrete examples."}),"\n"]}),"\n",(0,i.jsxs)(n.li,{children:["\n",(0,i.jsx)(n.p,{children:"A robot trained in simulation to navigate a warehouse fails when deployed to the real warehouse, even though the real warehouse layout matches the simulation exactly. List three physical phenomena that the simulation likely modeled inaccurately, and explain how each would cause failure."}),"\n"]}),"\n",(0,i.jsxs)(n.li,{children:["\n",(0,i.jsx)(n.p,{children:"Compare and contrast the failure modes of a software recommendation system versus a humanoid robot performing elder care. How does the nature of the failure mode change the ethical and engineering requirements for each system?"}),"\n"]}),"\n"]}),"\n",(0,i.jsx)(n.pre,{children:(0,i.jsx)(n.code,{children:"\n---\n\n```markdown\n"})})]})}function h(e={}){const{wrapper:n}={...(0,a.R)(),...e.components};return n?(0,i.jsx)(n,{...e,children:(0,i.jsx)(d,{...e})}):d(e)}},8453(e,n,t){t.d(n,{R:()=>o,x:()=>r});var s=t(6540);const i={},a=s.createContext(i);function o(e){const n=s.useContext(a);return s.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function r(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:o(e.components),s.createElement(a.Provider,{value:n},e.children)}}}]);